module top_module(
	input [31:0] instr,
	output branch, jump, MemToReg, MemWrite, RegDst, RegWrite, ALUSrc
);wire [5:0] op_code, func;
	assign op_code = instr[31:26];
	assign func = instr[5:0];
	wire add = ((op_code == 6'h00) & (func == 6'h20));
	wire sub = ((op_code == 6'h00) & (func == 6'h22));
	wire andd = ((op_code == 6'h00) & (func == 6'h24));
	wire orr = ((op_code == 6'h00) & (func == 6'h25));
	wire slt = ((op_code == 6'h00) & (func == 6'h2A));
	wire lw = (op_code == 6'h23);
	wire sw = (op_code == 6'h2B);
	wire beq = (op_code == 6'h04);
	wire addi = (op_code == 6'h08);
	wire jmp = (op_code == 6'h02);
	assign branch = beq;
	assign jump = jmp;
	assign MemToReg = lw;
	assign MemWrite = sw;
	assign RegDst = add | sub | andd | orr | slt;
	assign RegWrite = add | sub | andd | orr | slt | addi | lw;
	assign ALUSrc = addi | lw | sw;
endmodule
